import './App.css';
import { Navbar, Nav, Container, Button } from "react-bootstrap";
import 'bootstrap/dist/css/bootstrap.min.css';
import bank from './bank.avif';
import { HashRouter, Routes, Route, Link } from 'react-router-dom';
import Deposit from './deposit';
import Cashback from './cashback';
import Register from './register';
import Login from './login';
import Alldata from './alldata';
import TransactionHistory from './TransactionHistory';
import Profile from './Profile';
import Carousel from 'react-bootstrap/Carousel';
import Slide1 from './sile1.avif';
import Slide2 from './sile2.avif';
import Slide3 from './sile3.avif';
import { useState, useContext } from 'react';
import UserContext from './context';

function App() {
  let [isModel, setIsModel] = useState(true);
  const { user, logout } = useContext(UserContext);

  return (
    <HashRouter>
      <Navbar expand="lg" variant="dark" className="navbar-custom sticky-top">
        <Container>
          <Navbar.Brand as={Link} to="/" onClick={() => setIsModel(true)} className="navbar-brand-custom">
            <img
              src={bank}
              alt="Logo"
              className="d-inline-block align-top me-2"
              style={{ width: "35px", height: "35px", filter: "brightness(0) invert(1)" }}
            />
            SanZen Bank
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="navbar-nav" className="border-0" />
          <Navbar.Collapse id="navbar-nav">
            <Nav className="ms-auto align-items-center">
              <Nav.Link as={Link} to="/" onClick={() => setIsModel(true)} className="nav-link-custom">Home</Nav.Link>

              {!user ? (
                <>
                  <Nav.Link as={Link} to="/register" onClick={() => setIsModel(false)} className="nav-link-custom">Register</Nav.Link>
                  <Nav.Link as={Link} to="/login" onClick={() => setIsModel(false)} className="nav-link-custom">Login</Nav.Link>
                </>
              ) : (
                <>
                  <Nav.Link as={Link} to="/deposit" onClick={() => setIsModel(false)} className="nav-link-custom">Deposit</Nav.Link>
                  <Nav.Link as={Link} to="/cashback" onClick={() => setIsModel(false)} className="nav-link-custom">Withdraw</Nav.Link>
                  <Nav.Link as={Link} to="/history" onClick={() => setIsModel(false)} className="nav-link-custom">Tracking</Nav.Link>
                  <Nav.Link as={Link} to="/profile" onClick={() => setIsModel(false)} className="nav-link-custom">Profile</Nav.Link>
                  {user.role === 'admin' && (
                    <Nav.Link as={Link} to="/alldata" onClick={() => setIsModel(false)} className="nav-link-custom">All Data</Nav.Link>
                  )}
                  <div className="navbar-user-section ms-lg-3 mt-3 mt-lg-0">
                    {user.profilePhoto ? (
                      <img
                        src={`http://localhost:8080${user.profilePhoto}`}
                        alt="Profile"
                        className="rounded-circle navbar-profile-img"
                      />
                    ) : (
                      <div className="rounded-circle bg-primary d-flex align-items-center justify-content-center text-white" style={{ width: "35px", height: "35px", fontSize: "0.8rem" }}>
                        {user.name.charAt(0).toUpperCase()}
                      </div>
                    )}
                    <span className="text-light fw-500">Hi, {user.name.split(' ')[0]}</span>
                    <Button variant="outline-danger" size="sm" onClick={logout} className="logout-btn-custom ms-2">Logout</Button>
                  </div>
                </>
              )}
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      {isModel && (
        <Carousel className="custom-carousel" data-bs-theme="dark">
          <Carousel.Item className="custom-carousel-item">
            <img className="d-block w-100 custom-image" src={Slide1} alt="First slide" />
            <Carousel.Caption className="custom-caption">
              <h5 className="custom-caption-title">Register</h5>
              <p className="custom-caption-text">Time is money.</p>
            </Carousel.Caption>
          </Carousel.Item>

          <Carousel.Item className="custom-carousel-item">
            <img className="d-block w-100 custom-image" src={Slide2} alt="Second slide" />
            <Carousel.Caption className="custom-caption">
              <h5 className="custom-caption-title">Deposit</h5>
              <p className="custom-caption-text">Little by little, a little becomes a lot.</p>
            </Carousel.Caption>
          </Carousel.Item>

          <Carousel.Item className="custom-carousel-item">
            <img className="d-block w-100 custom-image" src={Slide3} alt="Third slide" />
            <Carousel.Caption className="custom-caption">
              <h5 className="custom-caption-title">Withdraw</h5>
              <p className="custom-caption-text">Do not spend your money before you have earned it.</p>
            </Carousel.Caption>
          </Carousel.Item>
        </Carousel>
      )}

      <Routes>
        <Route path="/register" element={<Register />} />
        <Route path="/login" element={<Login />} />
        <Route path="/deposit" element={<Deposit />} />
        <Route path="/cashback" element={<Cashback />} />
        <Route path="/history" element={<TransactionHistory />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/alldata" element={<Alldata />} />
      </Routes>

      <footer className="mt-5">&copy; SanZen Bank 2025</footer>
    </HashRouter>
  );
}

export default App;
